-- {"operators": "OUTER_JOIN,AGGREGATE", "complexity": "high", "is_incremental": true, "has_nulls": true, "has_cast": false, "has_case": false, "tables": "CUSTOMER,OORDER,ORDER_LINE", "delta": true}
SELECT c.C_W_ID, c.C_D_ID, c.C_ID, COUNT(ol.OL_NUMBER) AS lines, COALESCE(SUM(ol.OL_AMOUNT), 0) AS spent FROM d_CUSTOMER c LEFT JOIN d_OORDER o ON c.C_W_ID = o.O_W_ID AND c.C_D_ID = o.O_D_ID AND c.C_ID = o.O_C_ID LEFT JOIN d_ORDER_LINE ol ON o.O_W_ID = ol.OL_W_ID AND o.O_D_ID = ol.OL_D_ID AND o.O_ID = ol.OL_O_ID GROUP BY c.C_W_ID, c.C_D_ID, c.C_ID;
